fn solve(n: i64) -> bool {
    let digits: Vec<u64> = n.to_string().chars().map(|c| c.to_digit(10).unwrap()).collect();
    let sum: u64 = digits.iter().sum();
    let product: u64 = digits.iter().fold(1, |acc, &d| acc * d);
    let total = sum + product;
    total != 0 && n % total == 0
}
